import pytest

def test_happy_path_nested_dict():
    """Test getting a value from a deeply nested dictionary."""
    data = {
        'a': {
            'b': {
                'c': 42
            }
        }
    }
    assert deep_get(data, 'a.b.c') == 42

def test_happy_path_flat_dict():
    """Test getting a value from a flat dictionary."""
    data = {'key': 'value'}
    assert deep_get(data, 'key') == 'value'

def test_happy_path_missing_key_with_default():
    """Test getting a missing key with a default value."""
    data = {'a': {'b': 1}}
    assert deep_get(data, 'a.c') == None
    assert deep_get(data, 'a.c', 'default') == 'default'

def test_happy_path_empty_keys():
    """Test getting value when keys string is empty."""
    data = {'a': 1}
    assert deep_get(data, '') == None
    assert deep_get(data, '', default=42) == 42

def test_edge_case_non_dict_input():
    """Test behavior when input is not a dictionary."""
    assert deep_get('not_a_dict', 'key') == None
    assert deep_get('not_a_dict', 'key', default=42) == 42
    assert deep_get(123, 'key') == None
    assert deep_get(123, 'key', default='default') == 'default'

def test_edge_case_empty_dict():
    """Test behavior with empty dictionary."""
    assert deep_get({}, 'key') == None
    assert deep_get({}, 'key', default='default') == 'default'

def test_edge_case_multiple_levels():
    """Test with multiple levels of nesting."""
    data = {
        'level1': {
            'level2': {
                'level3': {
                    'level4': 'target'
                }
            }
        }
    }
    assert deep_get(data, 'level1.level2.level3.level4') == 'target'

def test_edge_case_invalid_key_format():
    """Test with invalid key format (contains spaces)."""
    data = {'a': {'b': 1}}
    assert deep_get(data, 'a . b') == None
    assert deep_get(data, 'a . b', default='default') == 'default'

def test_edge_case_none_as_default():
    """Test with None as default value."""
    data = {'a': {'b': 1}}
    assert deep_get(data, 'a.c', default=None) is None

def test_edge_case_empty_string_keys():
    """Test with empty string keys."""
    data = {'a': 1}
    assert deep_get(data, '.') == None
    assert deep_get(data, '.', default='default') == 'default'

def test_edge_case_multiple_dots_in_keys():
    """Test with multiple dots in keys (should be split correctly)."""
    data = {'a': {'b': {'c': 1}}}
    assert deep_get(data, 'a.b.c') == 1
    assert deep_get(data, 'a..b.c') == None  # Empty key after split
    assert deep_get(data, 'a..b.c', default='default') == 'default'

def test_edge_case_non_string_keys():
    """Test with non-string keys (though function expects string)."""
    data = {'a': {'b': 1}}
    with pytest.raises(TypeError):
        deep_get(data, 123)  # This would fail if we didn't handle it
    with pytest.raises(TypeError):
        deep_get(data, [1, 2, 3])
```

Note about the tests:
1. The tests cover happy paths (normal usage)
2. Edge cases (empty inputs, non-dict inputs, etc.)
3. Error cases (though the function doesn't raise exceptions, it returns defaults)
4. Some tests verify the behavior when keys are malformed (like containing spaces)

The tests assume that the function should:
- Return the value if all keys exist
- Return the default if any key doesn't exist
- Return the default if the input isn't a dictionary
- Handle empty keys appropriately

